#!/usr/bin/env node
// Claude Design AI - Component Generator
// Generates a complete design system with React + Tailwind components

const fs = require('fs');
const path = require('path');
const templates = require('./templates');

const OUTPUT_DIR = path.join(__dirname, '..', 'output');

function ensureDir(dir) {
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
}

function writeComponent(name, content, subdir = '') {
  const dir = subdir ? path.join(OUTPUT_DIR, subdir) : OUTPUT_DIR;
  ensureDir(dir);
  const filePath = path.join(dir, `${name}.tsx`);
  fs.writeFileSync(filePath, content, 'utf-8');
  return filePath;
}

function generateDesignSystem() {
  console.log('\n=== Claude Design AI - Design System Generator ===\n');

  const components = [
    { name: 'ThemeProvider', fn: templates.generateThemeProvider, dir: 'theme' },
    { name: 'DarkModeToggle', fn: templates.generateDarkModeToggle, dir: 'theme' },
    { name: 'Button', fn: templates.generateButton, dir: 'components' },
    { name: 'Card', fn: templates.generateCard, dir: 'components' },
    { name: 'Input', fn: templates.generateInput, dir: 'components' },
    { name: 'Navbar', fn: templates.generateNavbar, dir: 'layout' },
    { name: 'Hero', fn: templates.generateHeroSection, dir: 'layout' },
    { name: 'Icons', fn: templates.generateSvgIcons, dir: 'icons' },
  ];

  const generated = [];

  for (const comp of components) {
    const content = comp.fn();
    const filePath = writeComponent(comp.name, content, comp.dir);
    const lines = content.split('\n').length;
    generated.push({ name: comp.name, path: filePath, lines });
    console.log(`  [+] ${comp.dir}/${comp.name}.tsx (${lines} lines)`);
  }

  // Generate tailwind config
  const twConfig = templates.generateTailwindConfig();
  const twPath = path.join(OUTPUT_DIR, 'tailwind.config.js');
  fs.writeFileSync(twPath, twConfig, 'utf-8');
  console.log(`  [+] tailwind.config.js`);

  // Generate design tokens JSON
  const tokensPath = path.join(OUTPUT_DIR, 'design-tokens.json');
  fs.writeFileSync(tokensPath, JSON.stringify(templates.DESIGN_TOKENS, null, 2), 'utf-8');
  console.log(`  [+] design-tokens.json`);

  // Generate index barrel file
  const indexContent = `// Design System - Auto-generated by Claude Design AI
export { ThemeProvider, useTheme } from './theme/ThemeProvider';
export { DarkModeToggle } from './theme/DarkModeToggle';
export { Button } from './components/Button';
export { Card, CardHeader, CardTitle, CardContent } from './components/Card';
export { Input } from './components/Input';
export { Navbar } from './layout/Navbar';
export { Hero } from './layout/Hero';
export { IconHome, IconSearch, IconUser, IconSettings, IconMail } from './icons/Icons';
`;
  fs.writeFileSync(path.join(OUTPUT_DIR, 'index.ts'), indexContent, 'utf-8');
  console.log(`  [+] index.ts (barrel export)`);

  return generated;
}

function generateLandingPage() {
  console.log('\n=== Generating Landing Page Example ===\n');

  const page = `import React from 'react';
import { ThemeProvider } from './theme/ThemeProvider';
import { Navbar } from './layout/Navbar';
import { Hero } from './layout/Hero';
import { Card, CardHeader, CardTitle, CardContent } from './components/Card';
import { Button } from './components/Button';
import { Input } from './components/Input';
import { IconHome, IconSearch, IconUser, IconSettings, IconMail } from './icons/Icons';

const NAV_ITEMS = [
  { label: 'Features', href: '#features' },
  { label: 'Pricing', href: '#pricing' },
  { label: 'Docs', href: '#docs' },
  { label: 'Contact', href: '#contact' },
];

const FEATURES = [
  { icon: 'search', title: 'Smart Search', desc: 'AI-powered search finds exactly what you need.' },
  { icon: 'settings', title: 'Easy Setup', desc: 'Get started in under 60 seconds with zero config.' },
  { icon: 'mail', title: 'Notifications', desc: 'Real-time alerts keep your team in the loop.' },
];

const iconMap: Record<string, React.ReactNode> = {
  search: <IconSearch className="text-primary-600 dark:text-primary-400" />,
  settings: <IconSettings className="text-primary-600 dark:text-primary-400" />,
  mail: <IconMail className="text-primary-600 dark:text-primary-400" />,
};

export default function LandingPage() {
  return (
    <ThemeProvider>
      <div className="min-h-screen bg-white dark:bg-neutral-950">
        <Navbar brand="Acme" items={NAV_ITEMS} />

        <Hero
          headline="Build faster with AI"
          subheadline="Claude Design AI generates production-ready React components with Tailwind CSS, dark mode, and responsive layouts."
          ctaText="Get Started"
          ctaHref="#signup"
          secondaryCtaText="View Demo"
          secondaryCtaHref="#demo"
        />

        {/* Features grid */}
        <section id="features" className="mx-auto max-w-7xl px-4 py-24 sm:px-6 lg:px-8">
          <h2 className="text-center text-3xl font-bold text-neutral-900 dark:text-white">Features</h2>
          <div className="mt-12 grid gap-8 sm:grid-cols-2 lg:grid-cols-3">
            {FEATURES.map((f) => (
              <Card key={f.title} hoverable padding="lg">
                <CardHeader>
                  <div className="mb-3">{iconMap[f.icon]}</div>
                  <CardTitle>{f.title}</CardTitle>
                </CardHeader>
                <CardContent>{f.desc}</CardContent>
              </Card>
            ))}
          </div>
        </section>

        {/* CTA / Contact */}
        <section id="contact" className="bg-neutral-50 dark:bg-neutral-900">
          <div className="mx-auto max-w-md px-4 py-24 sm:px-6">
            <h2 className="text-center text-2xl font-bold text-neutral-900 dark:text-white">Stay Updated</h2>
            <div className="mt-8 space-y-4">
              <Input label="Email" type="email" placeholder="you@example.com" />
              <Button className="w-full">Subscribe</Button>
            </div>
          </div>
        </section>
      </div>
    </ThemeProvider>
  );
}`;

  const filePath = writeComponent('LandingPage', page, 'pages');
  console.log(`  [+] pages/LandingPage.tsx (${page.split('\n').length} lines)`);
  return filePath;
}

function printSummary(components) {
  const totalLines = components.reduce((sum, c) => sum + c.lines, 0);
  console.log('\n' + '='.repeat(50));
  console.log(`  Generated ${components.length} components + config files`);
  console.log(`  Total: ~${totalLines} lines of TypeScript/React`);
  console.log(`  Output: ${OUTPUT_DIR}/`);
  console.log('='.repeat(50));
}

// --- Main ---
if (require.main === module) {
  const components = generateDesignSystem();
  generateLandingPage();
  printSummary(components);
}

module.exports = { generateDesignSystem, generateLandingPage };
